//! BEEF Verification
//!
//! Validates incoming BEEF structure and merkle proofs.
//!
//! Structural verification (verify_valid) ALWAYS runs — catches incomplete
//! BEEFs with missing inputs, orphaned bump txids, broken dependency chains.
//!
//! Root verification (merkle roots vs block headers) runs when a header
//! provider is available. If no provider, structural checks still protect.
//!
//! Matches TS/Go/Rust reference toolboxes which always validate on internalizeAction.

use bsv_sdk::transaction::Beef;
use std::collections::HashSet;

use crate::error::{Error, Result};
use crate::services::chaintracker::{HeaderProvider, HeaderService};
use crate::types::BeefVerificationMode;

/// Verify an incoming BEEF for structural validity and merkle proof correctness.
///
/// Respects the `BeefVerificationMode`:
/// - **Skip**: no verification at all.
/// - **LogOnly**: run all checks but only log failures — never reject.
/// - **Strict**: run all checks and reject on any failure.
pub async fn verify_beef(
    beef: &mut Beef,
    header_provider: Option<&HeaderProvider>,
    mode: BeefVerificationMode,
    _known_txids: &HashSet<String>,
) -> Result<()> {
    // Skip mode — no verification at all
    if matches!(mode, BeefVerificationMode::Skip) {
        return Ok(());
    }

    let log_only = matches!(mode, BeefVerificationMode::LogOnly);

    if !beef.bumps.is_empty() {
        let validation = beef.verify_valid(false);
        if !validation.valid {
            let msg = "BEEF structure is invalid: missing inputs or broken proof chain";
            if log_only {
                worker::console_log!("BEEF verification warning (log_only): {}", msg);
                return Ok(());
            }
            return Err(Error::ValidationError(msg.to_string()));
        }

        if let Some(provider) = header_provider {
            for (height, root) in &validation.roots {
                match provider.is_valid_root_for_height(root, *height).await {
                    Ok(true) => { /* valid */ }
                    Ok(false) => {
                        let msg = format!("Invalid merkle root {} at height {}", root, height);
                        if log_only {
                            worker::console_log!("BEEF verification warning (log_only): {}", msg);
                            continue;
                        }
                        return Err(Error::ValidationError(msg));
                    }
                    Err(e) => {
                        let msg = format!("Header verification error at height {}: {}", height, e);
                        if log_only {
                            worker::console_log!("BEEF verification warning (log_only): {}", msg);
                            continue;
                        }
                        return Err(Error::InternalError(msg));
                    }
                }
            }
        }
    }

    Ok(())
}

// =============================================================================
// Tests
// =============================================================================

#[cfg(test)]
mod tests {
    use super::*;

    /// Real AtomicBEEF from production D1 (txid 576f57a0...537fa8).
    const REAL_BEEF_HEX: &str = "";

    #[test]
    fn test_real_beef_parses_as_atomic_beef() {
        let bytes = hex::decode(REAL_BEEF_HEX).expect("valid hex");
        assert_eq!(&bytes[0..4], &[0x02, 0x00, 0xBE, 0xEF]);
        let beef = Beef::from_binary(&bytes);
        assert!(beef.is_ok(), "Failed to parse: {:?}", beef.err());
    }

    #[test]
    fn test_real_beef_structural_validation() {
        let bytes = hex::decode(REAL_BEEF_HEX).expect("valid hex");
        let mut beef = Beef::from_binary(&bytes).expect("valid BEEF");
        let validation = beef.verify_valid(false);
        assert!(validation.valid, "Real BEEF failed structural validation");
        assert!(!validation.roots.is_empty(), "Should have merkle roots");
    }

    #[test]
    fn test_real_beef_has_correct_txid() {
        let bytes = hex::decode(REAL_BEEF_HEX).expect("valid hex");
        let beef = Beef::from_binary(&bytes).expect("valid BEEF");
        assert!(!beef.txs.is_empty(), "Should contain transactions");
    }

    #[test]
    fn test_real_beef_roots_are_valid_hex() {
        let bytes = hex::decode(REAL_BEEF_HEX).expect("valid hex");
        let mut beef = Beef::from_binary(&bytes).expect("valid BEEF");
        let validation = beef.verify_valid(false);
        for (height, root) in &validation.roots {
            assert!(*height > 0);
            assert_eq!(root.len(), 64);
            assert!(root.chars().all(|c| c.is_ascii_hexdigit()));
        }
    }

    #[test]
    fn test_wallet_bump_computes_correct_root() {
        use bsv_sdk::transaction::MerklePath;
        // BUMP from proven_txs for txid 44819054... at height 943061
        // Stored merkle_root: d0ae5d1767a07246f7a274f8ef8395de5c28be22fc0404fd451bcd5a9bede573
        let bump_hex = "";
        let txid = "44819054e1ad7312081f93434fb9dc5a2595def8c7dd9c7821f3de328be2c75a";
        let expected_root = "d0ae5d1767a07246f7a274f8ef8395de5c28be22fc0404fd451bcd5a9bede573";

        let bump = MerklePath::from_hex(bump_hex).expect("valid BUMP hex");
        eprintln!("BUMP block_height: {}", bump.block_height);
        assert_eq!(bump.block_height, 943061);

        let computed_root = bump.compute_root(Some(txid)).expect("compute_root");
        eprintln!("Computed root: {}", computed_root);
        eprintln!("Expected root: {}", expected_root);
        assert_eq!(
            computed_root.to_lowercase(),
            expected_root.to_lowercase(),
            "BUMP computes wrong merkle root!"
        );
    }

    #[test]
    fn test_real_beef_bumps_present() {
        let bytes = hex::decode(REAL_BEEF_HEX).expect("valid hex");
        let beef = Beef::from_binary(&bytes).expect("valid BEEF");
        assert!(!beef.bumps.is_empty(), "Should have BUMPs");
    }

    #[test]
    fn test_truncated_beef_fails() {
        let bytes = hex::decode(REAL_BEEF_HEX).expect("valid hex");
        let truncated = &bytes[..bytes.len() / 2];
        assert!(Beef::from_binary(truncated).is_err());
    }

    #[test]
    fn test_garbage_bytes_not_beef() {
        let garbage = vec![0xDE, 0xAD, 0xBE, 0xEF, 0x00, 0x01, 0x02, 0x03];
        assert!(Beef::from_binary(&garbage).is_err());
    }
}
